#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use HTML::Entities;

my $cgi = CGI->new;
my $comment = $cgi->param('comment') || '';

$comment = encode_entities($comment);

$comment =~ s/&lt;b&gt;/<b>/gi;
$comment =~ s/&lt;\/b&gt;/<\/b>/gi;
$comment =~ s/&lt;i&gt;/<i>/gi;
$comment =~ s/&lt;\/i&gt;/<\/i>/gi;
$comment =~ s/&lt;u&gt;/<u>/gi;
$comment =~ s/&lt;\/u&gt;/<\/u>/gi;
$comment =~ s/&lt;br&gt;/<br>/gi;
$comment =~ s/&lt;br\/&gt;/<br\/>/gi;
$comment =~ s/&lt;p&gt;/<p>/gi;
$comment =~ s/&lt;\/p&gt;/<\/p>/gi;

print "Content-type: text/html\n\n";
print "<div>$comment</div>";